record PriceUpdate(String symbol, double price, double change, String timestamp) {}

@Controller
class PriceSubscriptionController {

    @SubscriptionMapping
    public Flux<PriceUpdate> priceUpdate(@Argument String symbol) {
        return Flux.interval(Duration.ofSeconds(1))
            .map(tick -> new PriceUpdate(
                symbol,
                2834.50 + tick * 0.10, // simulated price drift
                tick * 0.10,
                Instant.now().toString()
            ))
            .take(5); // finite for testing (production: no take)
    }
}

@SpringBootTest
class PriceSubscriptionTest {
    @Autowired PriceSubscriptionController ctrl;

    @Test void subscription_emits5Updates() {
        Flux<PriceUpdate> flux = ctrl.priceUpdate("RELIANCE");
        StepVerifier.create(flux)
            .expectNextMatches(p -> p.symbol().equals("RELIANCE"))
            .expectNextMatches(p -> p.price() > 2834.50)
            .expectNextCount(3) // 3 more updates
            .verifyComplete();
    }

    @Test void subscription_symbolPassedThrough() {
        Flux<PriceUpdate> flux = ctrl.priceUpdate("TCS");
        StepVerifier.create(flux.take(1))
            .expectNextMatches(p -> "TCS".equals(p.symbol()))
            .verifyComplete();
    }
}

