record PaymentStatus(String paymentId, String status, long timestamp) {
    boolean isFinal() { return "CAPTURED".equals(status) || "FAILED".equals(status); }
}

@Service
class PaymentEventPublisher {
    // Sinks.Many: non-blocking, thread-safe event publisher
    private final Sinks.Many<PaymentStatus> sink =
        Sinks.many().multicast().onBackpressureBuffer();

    // Push a payment status update:
    public void publishStatus(String paymentId, String status) {
        PaymentStatus event = new PaymentStatus(paymentId, status, System.currentTimeMillis());
        sink.tryEmitNext(event);
    }

    // Expose as Flux for @SubscriptionMapping:
    public Flux<PaymentStatus> asFlux() {
        return sink.asFlux();
    }
}

