import java.time.Duration;

@Service
class RzpEventBus {
    private final Sinks.Many<PaymentStatus> sink = Sinks.many().multicast().onBackpressureBuffer();
    public void publish(String id, String status) { sink.tryEmitNext(new PaymentStatus(id, status, System.currentTimeMillis())); }
    public Flux<PaymentStatus> asFlux() { return sink.asFlux(); }
}

@Controller
class RzpSubscriptionCtrl {
    private final RzpEventBus bus;
    RzpSubscriptionCtrl(RzpEventBus b) { bus = b; }

    @SubscriptionMapping
    public Flux<PaymentStatus> paymentStatus(@Argument String paymentId) {
        return bus.asFlux()
            .filter(s -> s.paymentId().equals(paymentId)) // only this payment
            .takeUntil(PaymentStatus::isFinal);             // stop on terminal
    }
}

@SpringBootTest
class PaymentSubscriptionTest {
    @Autowired RzpEventBus bus;
    @Autowired RzpSubscriptionCtrl ctrl;

    @Test void receivesCorrectPayment() {
        Flux<PaymentStatus> sub = ctrl.paymentStatus("PAY-100").take(1);
        StepVerifier.create(sub)
            .then(() -> bus.publish("PAY-100", "INITIATED"))
            .expectNextMatches(s -> "PAY-100".equals(s.paymentId()))
            .verifyComplete();
    }

    @Test void stopsOnTerminalStatus() {
        Flux<PaymentStatus> sub = ctrl.paymentStatus("PAY-200");
        StepVerifier.create(sub)
            .then(() -> { bus.publish("PAY-200", "INITIATED"); bus.publish("PAY-200", "CAPTURED"); })
            .expectNextCount(2) // INITIATED + CAPTURED (inclusive in takeUntil)
            .verifyComplete();  // stream completed after CAPTURED
    }

    @Test void ignoresOtherPayments() {
        Flux<PaymentStatus> sub = ctrl.paymentStatus("PAY-300").take(1);
        StepVerifier.create(sub)
            .then(() -> {
                bus.publish("PAY-OTHER", "INITIATED"); // different payment — filtered out
                bus.publish("PAY-300", "INITIATED");   // this one passes through
            })
            .expectNextMatches(s -> "PAY-300".equals(s.paymentId()))
            .verifyComplete();
    }
}

