import reactor.core.publisher.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import reactor.test.StepVerifier;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;
import java.util.*;
import java.util.concurrent.CopyOnWriteArrayList;

@Service
class ResilientPriceSubscription {
    private final Set<String> validSymbols = Set.of("RELIANCE", "TCS", "INFY", "HDFC", "WIPRO");
    private final List<String> errorLog = new CopyOnWriteArrayList<>();

    public Flux<String> priceUpdates(String symbol) {
        return Flux.defer(() -> {
            if (!validSymbols.contains(symbol.toUpperCase())) {
                return Flux.error(new IllegalArgumentException("Unknown symbol: " + symbol));
            }
            return Flux.interval(Duration.ofMillis(100))
                .map(t -> symbol + ": ₹" + (2834.50 + t))
                .take(3);
        })
        .doOnError(e -> errorLog.add("ERROR for symbol " + symbol + ": " + e.getMessage()))
        .onErrorResume(IllegalArgumentException.class, e ->
            // Fallback: emit an error message and complete
            Flux.just("Symbol '" + symbol + "' not found. Check symbol name."));
    }

    public List<String> getErrorLog() { return Collections.unmodifiableList(errorLog); }
}

@SpringBootTest
class SubscriptionErrorTest {
    @Autowired ResilientPriceSubscription sub;

    @Test void validSymbol_emitsUpdates() {
        StepVerifier.create(sub.priceUpdates("RELIANCE"))
            .expectNextMatches(s -> s.startsWith("RELIANCE"))
            .expectNextCount(2)
            .verifyComplete();
    }
    @Test void invalidSymbol_getsFallback() {
        StepVerifier.create(sub.priceUpdates("INVALID_SYMBOL"))
            .expectNextMatches(s -> s.contains("not found"))
            .verifyComplete(); // fallback emits one message then completes
    }
    @Test void invalidSymbol_errorLogged() {
        sub.priceUpdates("BAD_TICKER").blockLast();
        assertTrue(sub.getErrorLog().stream().anyMatch(e -> e.contains("BAD_TICKER")));
    }
}

