import reactor.test.StepVerifier;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
class SubscriptionAuthService {
    private final Map<String, String> validTokens = Map.of(
        "token-ACC-001", "ACC-001",
        "token-ACC-002", "ACC-002"
    );

    public Optional<String> validateToken(String token) {
        return Optional.ofNullable(validTokens.get(token));
    }
}

@Service
class SecureTradeSubscription {
    private final TradeEventBus bus;
    private final SubscriptionAuthService auth;

    SecureTradeSubscription(TradeEventBus b, SubscriptionAuthService a) { bus=b; auth=a; }

    public Flux<Trade> secureTradeUpdates(String token, String requestedAccountId) {
        Optional<String> accountId = auth.validateToken(token);
        if (accountId.isEmpty()) {
            return Flux.error(new SecurityException("Invalid or expired token"));
        }
        // Can only see YOUR own account's trades:
        String authenticatedAccountId = accountId.get();
        if (!authenticatedAccountId.equals(requestedAccountId)) {
            return Flux.error(new SecurityException("Access denied: cannot view account " + requestedAccountId));
        }
        return bus.asFlux().filter(t -> t.accountId().equals(authenticatedAccountId));
    }
}

@SpringBootTest
class SecureSubscriptionTest {
    @Autowired TradeEventBus bus;
    @Autowired SecureTradeSubscription secureSub;

    @Test void validToken_receivesTrades() {
        Flux<Trade> trades = secureSub.secureTradeUpdates("token-ACC-001", "ACC-001").take(1);
        StepVerifier.create(trades)
            .then(() -> bus.publish(new Trade("T1","RELIANCE",10,2834.0,"BUY","ACC-001")))
            .expectNextMatches(t -> "ACC-001".equals(t.accountId()))
            .verifyComplete();
    }
    @Test void invalidToken_errorsOut() {
        Flux<Trade> trades = secureSub.secureTradeUpdates("bad-token", "ACC-001");
        StepVerifier.create(trades)
            .expectError(SecurityException.class)
            .verify();
    }
}

