import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import reactor.test.StepVerifier;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

@Service
class SubscriberRegistry {
    private final ConcurrentHashMap<String, AtomicInteger> counts = new ConcurrentHashMap<>();
    public void register(String key) { counts.computeIfAbsent(key, k -> new AtomicInteger(0)).incrementAndGet(); }
    public void unregister(String key) { counts.computeIfAbsent(key, k -> new AtomicInteger(0)).decrementAndGet(); }
    public int count(String key) { return counts.getOrDefault(key, new AtomicInteger(0)).get(); }
}

@Controller
class ZerodhaCompleteSubscription {
    private final TradeEventBus tradeBus;
    private final SubscriberRegistry registry;
    ZerodhaCompleteSubscription(TradeEventBus t, SubscriberRegistry r) { tradeBus=t; registry=r; }

    @SubscriptionMapping
    public Flux<Trade> tradeUpdates(@Argument String accountId) {
        return tradeBus.asFlux()
            .filter(t -> accountId == null || t.accountId().equals(accountId))
            .doOnSubscribe(s -> registry.register("trade:" + accountId))
            .doOnCancel(() -> registry.unregister("trade:" + accountId));
    }

    @SubscriptionMapping
    public Flux<PriceUpdate> priceUpdate(@Argument String symbol) {
        return Flux.interval(Duration.ofMillis(100))
            .map(t -> new PriceUpdate(symbol, 2834.50 + t * 0.01, t * 0.01, java.time.Instant.now().toString()))
            .doOnSubscribe(s -> registry.register("price:" + symbol))
            .doOnCancel(() -> registry.unregister("price:" + symbol))
            .take(5); // finite for test
    }
}

@SpringBootTest
class ZerodhaCompleteSubTest {
    @Autowired TradeEventBus tradeBus;
    @Autowired ZerodhaCompleteSubscription sub;
    @Autowired SubscriberRegistry registry;

    @Test void tradeUpdates_filtered() {
        Flux<Trade> flux = sub.tradeUpdates("ACC-100").take(1);
        StepVerifier.create(flux)
            .then(() -> tradeBus.publish(new Trade("T","RELIANCE",10,2834.0,"BUY","ACC-100")))
            .expectNextCount(1).verifyComplete();
    }
    @Test void priceUpdate_emits() {
        StepVerifier.create(sub.priceUpdate("TCS"))
            .expectNextMatches(p -> "TCS".equals(p.symbol()))
            .expectNextCount(4).verifyComplete();
    }
    @Test void registry_tracksSubscribers() {
        sub.priceUpdate("NIFTY").blockLast(); // subscribes and completes
        // After completion registry may be 0 (doOnCancel on complete)
        assertTrue(registry.count("price:NIFTY") >= 0);
    }
    @Test void tradeFilter_blocksOtherAccounts() {
        Flux<Trade> flux = sub.tradeUpdates("ACC-200").take(1);
        StepVerifier.create(flux)
            .then(() -> {
                tradeBus.publish(new Trade("TX","HDFC",5,1650.0,"SELL","ACC-999")); // different
                tradeBus.publish(new Trade("TY","HDFC",5,1650.0,"SELL","ACC-200")); // mine
            })
            .expectNextMatches(t -> "ACC-200".equals(t.accountId()))
            .verifyComplete();
    }
}

