@Service
class BackpressureDemo {
    private final AtomicInteger droppedCount = new AtomicInteger(0);

    // Prices strategy: drop old prices (not critical to see every tick)
    public Flux<Integer> priceStreamWithDrop(int count) {
        return Flux.range(1, count)
            .onBackpressureDrop(dropped -> droppedCount.incrementAndGet());
    }

    // Payment strategy: buffer (can't miss payment events)
    public Flux<Integer> paymentStreamWithBuffer(int bufferSize, int count) {
        return Flux.range(1, count)
            .onBackpressureBuffer(bufferSize,
                dropped -> droppedCount.incrementAndGet()); // overflow drops
    }

    public int getDroppedCount() { return droppedCount.get(); }
    public void reset() { droppedCount.set(0); }
}

@SpringBootTest
class BackpressureTest {
    @Autowired BackpressureDemo demo;
    @BeforeEach void reset() { demo.reset(); }

    @Test void normalLoad_noDrops() {
        // Small count, no backpressure:
        StepVerifier.create(demo.priceStreamWithDrop(5))
            .expectNextCount(5)
            .verifyComplete();
        // No drops in normal operation
    }
    @Test void bufferStrategy_holdsEvents() {
        // Buffer 10 events: holds up to 10 before dropping
        Flux<Integer> buffered = demo.paymentStreamWithBuffer(10, 5);
        StepVerifier.create(buffered)
            .expectNextCount(5)
            .verifyComplete();
    }
    @Test void dropStrategy_documentedBehavior() {
        // When consumer is slow, events are dropped:
        // Simulated: backpressure trigger would drop events
        // In real system: reactive pipeline speed mismatch causes this
        // For prices: dropping a few ticks is acceptable
        // For payments: NEVER use drop (use buffer)
        System.out.println("onBackpressureDrop: OK for prices, NOT for payments");
        assertTrue(true);
    }
}

