import java.util.concurrent.atomic.AtomicInteger;

@Service class SynthPayBus {
    Sinks.Many<PaymentStatus> s=Sinks.many().multicast().onBackpressureBuffer();
    void pub(String id,String status){s.tryEmitNext(new PaymentStatus(id,status,System.currentTimeMillis()));}
    Flux<PaymentStatus> flux(){return s.asFlux();}
}

@Service class SynthRegistry {
    ConcurrentHashMap<String,AtomicInteger> c=new ConcurrentHashMap<>();
    void inc(String k){c.computeIfAbsent(k,x->new AtomicInteger(0)).incrementAndGet();}
    void dec(String k){c.computeIfAbsent(k,x->new AtomicInteger(0)).decrementAndGet();}
    int get(String k){return c.getOrDefault(k,new AtomicInteger(0)).get();}
}

@Service class SynthAuth {
    boolean valid(String u){return u!=null&&(u.startsWith("U-"));}
}

@org.springframework.stereotype.Controller
class SynthSubCtrl {
    SynthPayBus bus;SynthRegistry reg;SynthAuth auth;
    SynthSubCtrl(SynthPayBus b,SynthRegistry r,SynthAuth a){bus=b;reg=r;auth=a;}

    @org.springframework.graphql.data.method.annotation.SubscriptionMapping
    Flux<PaymentStatus> synthPayment(
            @org.springframework.graphql.data.method.annotation.Argument String userId,
            @org.springframework.graphql.data.method.annotation.Argument String paymentId){
        if(!auth.valid(userId)) return Flux.error(new SecurityException("bad user"));
        return bus.flux().filter(s->s.paymentId().equals(paymentId)).takeUntil(PaymentStatus::isFinal)
            .doOnSubscribe(x->reg.inc("payment")).doOnCancel(()->reg.dec("payment"));
    }

    @org.springframework.graphql.data.method.annotation.SubscriptionMapping
    Flux<PriceUpdate> synthPrice(@org.springframework.graphql.data.method.annotation.Argument String symbol){
        return Flux.interval(Duration.ofMillis(50)).take(3)
            .map(t->new PriceUpdate(symbol,2834.0+t,t.doubleValue(),java.time.Instant.now().toString()))
            .doOnSubscribe(x->reg.inc("price:"+symbol)).doOnCancel(()->reg.dec("price:"+symbol));
    }
}

